#include <libavcodec/avcodec.h>
#include <libavformat/avformat.h>
#include <stdio.h>

int main(int argc, char **argv) {
    if (argc < 3) {
        printf("الاستخدام: %s <ملف_مدخل> <ملف_خرج.m4a>\n", argv[0]);
        return 1;
    }

    AVFormatContext *in_fmt = NULL;
n    AVFormatContext *out_fmt = NULL;
n    AVCodecContext *dec_ctx = NULL;
    AVCodecContext *enc_ctx = NULL;
    const AVCodec *dec_codec = NULL;
    const AVCodec *enc_codec = NULL;
    AVFrame *frame = av_frame_alloc();
    AVPacket *pkt = av_packet_alloc();
    AVFrame *enc_frame = av_frame_alloc();

    // فتح المدخل
    avformat_open_input(&in_fmt, argv[1], NULL, NULL);
    avformat_find_stream_info(in_fmt, NULL);

    int stream_idx = av_find_best_stream(in_fmt, AVMEDIA_TYPE_AUDIO, -1, -1, 0, NULL);

    // decoder
    dec_codec = avcodec_find_decoder(in_fmt->streams[stream_idx]->codecpar->codec_id);
    dec_ctx = avcodec_alloc_context3(dec_codec);
    avcodec_parameters_to_context(dec_ctx, in_fmt->streams[stream_idx]->codecpar);
    avcodec_open2(dec_ctx, dec_codec, NULL);

    // encoder AAC
    enc_codec = avcodec_find_encoder_by_name("aac");
    enc_ctx = avcodec_alloc_context3(enc_codec);
    avcodec_parameters_to_context(enc_ctx, in_fmt->streams[stream_idx]->codecpar);
    avcodec_open2(enc_ctx, enc_codec, NULL);

    // الخرج
    const AVOutputFormat *out_fmt_desc = av_guess_format(NULL, NULL, argv[2]);
    avformat_alloc_output_context2(&out_fmt, out_fmt_desc, NULL, argv[2]);
    AVStream *out_stream = avformat_new_stream(out_fmt, NULL);
    avcodec_parameters_copy(out_stream->codecpar, in_fmt->streams[stream_idx]->codecpar);
    avformat_write_header(out_fmt);

    // تحويل
    while (av_read_frame(in_fmt, pkt) >= 0) {
        if (pkt->stream_index == stream_idx) {
            avcodec_send_packet(dec_ctx, pkt);
            while (avcodec_receive_frame(dec_ctx, frame) >= 0) {
                avcodec_send_frame(enc_ctx, frame);
                while (avcodec_receive_frame(enc_ctx, enc_frame) >= 0) {
                    av_packet_unref(enc_frame->pkt);
                }
            }
        }
        av_packet_unref(pkt);
    }

