n    avformat_close_input(&in_fmt);
    printf("تم تحويل إلى AAC بنجاح\n");

    av_frame_free(&frame);
    av_frame_free(&enc_frame);
    av_packet_free(&pkt);
    avcodec_free_context(&dec_ctx);
    avcodec_free_context(&enc_ctx);
    avformat_free_context(out_fmt);
    return 0;
